// // This module converts a 5-bit binary input to a 3-bit status output based on current levels. The output is 000 for low (0-10), 001 for normal (11-20), 010 for high (21-30), and 011 for overload (31-31). However, if the input exceeds 31, the output will be 000 (low).
module current_sensor(  
    input [4:0] current_level,  
    output reg [2:0] status  
);  
always @(*) begin  
    if (current_level <= 5'd10)  
        status = 3'b000; // Low  
    else if (current_level <= 5'd20)  
        status = 3'b001; // Normal  
    else if (current_level <= 5'd30)  
        status = 3'b010; // High  
    else  
        status = 3'b011; // Overload  
end  
endmodule
